static void _b(EPD*e){while(e->digital_read(e->busy_pin)==0){e->send_command(e,0x71);e->delay_ms(100);}}
static void _fr(EPD*e){e->send_command(e,0x82);e->send_data(e,0x00);e->send_command(e,0x50);e->send_data(e,0x97);e->send_command(e,0x20);e->send_data_buf(e,lv,42);e->send_command(e,0x21);e->send_data_buf(e,lw,42);e->send_command(e,0x22);e->send_data_buf(e,lb,42);e->send_command(e,0x23);e->send_data_buf(e,lr,42);e->send_command(e,0x24);e->send_data_buf(e,ln,42);}
int EPD_2in9d_Init(EPD *epd){if(!epd)return EPD_ERROR;epd->width=128;epd->height=296;epd->rst_pin=EPD_RST_PIN;epd->dc_pin=EPD_DC_PIN;epd->cs_pin=EPD_CS_PIN;epd->busy_pin=EPD_BUSY_PIN;epd->pwr_pin=EPD_PWR_PIN;if(epd_setup_default_hal(epd)!=EPD_OK)return EPD_ERROR;epd_reset(epd);epd_send_command(epd,0x01);epd_send_data(epd,0x03);epd_send_data(epd,0x00);epd_send_data(epd,0x2B);epd_send_data(epd,0x2B);epd_send_data(epd,0x03);epd_send_command(epd,0x06);epd_send_data(epd,0x17);epd_send_data(epd,0x17);epd_send_data(epd,0x17);epd_send_command(epd,0x04);_b(epd);epd_send_command(epd,0x00);epd_send_data(epd,0xBF);epd_send_data(epd,0x0D);epd_send_command(epd,0x30);epd_send_data(epd,0x3A);epd_send_command(epd,0x61);epd_send_data(epd,128);epd_send_data(epd,0x01);epd_send_data(epd,0x28);epd_send_command(epd,0x82);epd_send_data(epd,0x28);return EPD_OK;}
void EPD_2in9d_Clear(EPD *epd){if(!epd){return;}int sz=epd_linewidth(128)*296;uint8_t*z=(uint8_t*)calloc(1,sz);uint8_t*w=(uint8_t*)malloc(sz);if(!z||!w){free(z);free(w);return;}memset(w,0xFF,sz);epd_send_command(epd,0x10);epd_send_data_buf(epd,z,sz);epd->delay_ms(10);epd_send_command(epd,0x13);epd_send_data_buf(epd,w,sz);epd->delay_ms(10);free(z);free(w);_fr(epd);epd_send_command(epd,0x12);epd->delay_ms(100);_b(epd);}
void EPD_2in9d_Display(EPD *epd, const uint8_t *img){if(!epd||!img){return;}int sz=epd_linewidth(128)*296;uint8_t*z=(uint8_t*)calloc(1,sz);if(!z)return;epd_send_command(epd,0x10);epd_send_data_buf(epd,z,sz);epd->delay_ms(10);free(z);epd_send_command(epd,0x13);epd_send_data_buf(epd,img,sz);epd->delay_ms(10);_fr(epd);epd_send_command(epd,0x12);epd->delay_ms(100);_b(epd);}
void EPD_2in9d_Sleep(EPD *epd){if(!epd)return;epd_send_command(epd,0x50);epd_send_data(epd,0xF7);epd_send_command(epd,0x02);epd_send_command(epd,0x07);epd_send_data(epd,0xA5);epd->delay_ms(2000);epd_teardown_default_hal(epd);}
